const e={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Simuliere G-code offline — füge ein Programm ein oder schreibe es und sieh den Werkzeugkopf-Pfad, die Begrenzungsbox, Verfahr- und Extrusionssummen sowie eine Zeitschätzung, ohne den Drucker anzufassen. Durchstöbere die integrierte Makro-Bibliothek als Referenz."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über den Macro Designer"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Verwendung"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Tippe oder füge G-code in den Editor ein (ein Beispielquadrat ist zu Beginn geladen)."}},{t:0,b:{t:2,i:[{t:3}],s:"Drücke Simulieren — der 2D-Pfad und die Statistiken werden aktualisiert."}},{t:0,b:{t:2,i:[{t:3}],s:"Durchgezogene Linien sind Extrusionsbewegungen; schwache gestrichelte Linien sind Verfahrwege."}},{t:0,b:{t:2,i:[{t:3}],s:"Durchstöbere die Makro-Bibliothek und füge eines ein, um von dessen Befehlen aus zu starten."}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"Der Simulator"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Er führt das Programm auf einem virtuellen Werkzeugkopf aus: G0/G1-Bewegungen, G90/G91 (absolut/relativ), M82/M83 (Extrudermodus), G92 (Position setzen) und G28 (Homing → Ursprung). Er meldet den Pfad, die Begrenzungsbox, den gesamten Verfahrweg und die Extrusion, eine grobe Zeitschätzung aus den Vorschüben sowie einen Zeitablauf pro Befehl. Nichts wird an den Drucker gesendet."}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"Pfad & Zeit"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Die 2D-Ansicht ist der XY-Pfad (Z ist in den Grenzen enthalten). Die Zeitschätzung teilt die Länge jeder Bewegung durch ihren Vorschub — sie ignoriert die Beschleunigung, also ist sie eine grobe Untergrenze, nicht die exakte Druckzeit. Befehle, die der Simulator nicht modelliert (z. B. M-codes, übergeordnete Makros), werden als Warnungen aufgeführt und übersprungen."}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"Makro-Bibliothek"}},body:{t:0,b:{t:2,i:[{t:3}],s:'Eine Referenzsammlung gängiger Klipper-Makros mit ihrem Namen, ihrer Funktion und den benötigten Konfigurationssektionen. "Einfügen" setzt die übergeordneten Befehle eines Makros als Ausgangspunkt in den Editor — beachte, dass diese sich auf dem Drucker weiter aufschlüsseln (vollständige Jinja-/Makro-Expansion folgt).'}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Die zeilenweise Bewegungssprache, die der Drucker ausführt (Bewegungen, Temperaturen, Lüfter, …)."}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"Vorschub (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Bewegungsgeschwindigkeit in mm/min — F1200 sind 20 mm/s. Legt fest, wie schnell jede Bewegung läuft."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"Makro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein benannter, wiederverwendbarer Befehl (z. B. QUAD_GANTRY_LEVEL), der sich zu einer Folge von G-code aufschlüsselt."}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"Simulieren"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"Simuliere…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"Beispiel laden"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Leeren"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"Integrierte Makros"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Makros durchstöbern…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"In Editor einfügen"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Benötigt: "},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Simulation"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Bewegungen"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm Verfahrweg"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm extrudiert"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"~"},{t:4,k:"s"},{t:3,v:" s"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"Grenzen"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Keine Bewegungen zum Simulieren."}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"Werkzeugkopf-Pfad (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"Führe eine Simulation aus, um den Pfad zu sehen."}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"Zeitablauf"}},line:{t:0,b:{t:2,i:[{t:3}],s:"Zeile"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"Befehl"}},action:{t:0,b:{t:2,i:[{t:3}],s:"Aktion"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"Warnungen"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"Dieses Makro erklären"}},travel:{t:0,b:{t:2,i:[{t:3,v:"Eilgang nach X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" mit "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"Druckbewegung — "},{t:4,k:"e"},{t:3,v:" mm über "},{t:4,k:"d"},{t:3,v:" mm nach X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" mit "},{t:4,k:"f"},{t:3,v:" mm/min extrudieren"}]}},retract:{t:0,b:{t:2,i:[{t:4,k:"e"},{t:3,v:" mm zurückziehen"}]}},prime:{t:0,b:{t:2,i:[{t:4,k:"e"},{t:3,v:" mm an Ort und Stelle extrudieren"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"Keine Bewegung"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Auf absolute Positionierung umschalten (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Auf relative Positionierung umschalten (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"Auf absolute Extrusion umschalten (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"Auf relative Extrusion umschalten (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"Aktuelle Position setzen (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"Achsen referenzieren (G28) → Ursprung"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"ABS"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"REL"}},cum:{t:0,b:{t:2,i:[{t:3,v:"bisher: "},{t:4,k:"d"},{t:3,v:" mm · "},{t:4,k:"e"},{t:3,v:" mm · ~"},{t:4,k:"s"},{t:3,v:" s"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"Zeilen mit ungelösten Ausdrücken oder Jinja-Steuerfluss werden nicht simuliert und hier weggelassen."}}},live:{label:{t:0,b:{t:2,i:[{t:3}],s:"Vom Drucker"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Eines deiner installierten Makros wählen…"}},hint:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" Makros auf dem Drucker gefunden — wähle eines, um seinen G-Code zu laden und zu simulieren."}]}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Drucker nicht erreichbar — verbinde dich, um deine Makros zu laden."}},params:{t:0,b:{t:2,i:[{t:3}],s:"Makro-Parameter"}}},limits:{title:{t:0,b:{t:2,i:[{t:3}],s:"Außerhalb / zu schnell"}},oob:{t:0,b:{t:2,i:[{t:3,v:"Zeile "},{t:4,k:"line"},{t:3,v:": "},{t:4,k:"axis"},{t:3,v:"="},{t:4,k:"value"},{t:3,v:" liegt außerhalb des Bauraums ("},{t:4,k:"min"},{t:3,v:"…"},{t:4,k:"max"},{t:3,v:" mm)."}]}},overSpeed:{t:0,b:{t:2,i:[{t:3,v:"Zeile "},{t:4,k:"line"},{t:3,v:": "},{t:4,k:"value"},{t:3,v:" mm/s überschreitet das Limit von "},{t:4,k:"limit"},{t:3,v:" mm/s (Klipper begrenzt es)."}]}},buildArea:{t:0,b:{t:2,i:[{t:3,v:"Bauraum "},{t:4,k:"x"},{t:3,v:"×"},{t:4,k:"y"},{t:3,v:" mm"}]}}}}};export{e as default};
